script:
export const meta = {
  name: 'prompt-caching-deep-research',
  description: 'Deep research: Claude vs OpenAI prompt caching strategies 2025-2026',
  phases: [
    { title: 'Plan' },
    { title: 'Search' },
    { title: 'Fetch' },
    { title: 'Verify' },
    { title: 'Synthesize' }
  ]
}

const SEARCH_SCHEMA = {
  type: 'object',
  properties: {
    queries: { type: 'array', items: { type: 'string' } },
    rationale: { type: 'string' }
  },
  required: ['queries', 'rationale']
}

const SEARCH_RESULTS_SCHEMA = {
  type: 'object',
  properties: {
    results: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          url: { type: 'string' },
          title: { type: 'string' },
          snippet: { type: 'string' },
          relevance: { type: 'string' }
        },
        required: ['url', 'title', 'snippet', 'relevance']
      }
    }
  },
  required: ['results']
}

const FETCH_SCHEMA = {
  type: 'object',
  properties: {
    url: { type: 'string' },
    title: { type: 'string' },
    key_facts: { type: 'array', items: { type: 'string' } },
    relevant_quotes: { type: 'array', items: { type: 'string' } },
    cache_details: {
      type: 'object',
      properties: {
        ttl: { type: 'string' },
        pricing: { type: 'string' },
        breakpoints: { type: 'string' },
        prefix_requirements: { type: 'string' }
      }
    }
  },
  required: ['url', 'title', 'key_facts']
}

const VERIFY_SCHEMA = {
  type: 'object',
  properties: {
    claim: { type: 'string' },
    verdict: { type: 'string', enum: ['confirmed', 'refuted', 'uncertain'] },
    evidence: { type: 'string' },
    sources: { type: 'array', items: { type: 'string' } }
  },
  required: ['claim', 'verdict', 'evidence']
}

const SYNTHESIS_SCHEMA = {
  type: 'object',
  properties: {
    summary: { type: 'string' },
    findings: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          topic: { type: 'string' },
          detail: { type: 'string' },
          sources: { type: 'array', items: { type: 'string' } }
        },
        required: ['topic', 'detail', 'sources']
      }
    },
    sources: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          url: { type: 'string' },
          title: { type: 'string' },
          credibility: { type: 'string' }
        },
        required: ['url', 'title']
      }
    },
    caveats: { type: 'array', items: { type: 'string' } },
    actionable_guidance: { type: 'array', items: { type: 'string' } }
  },
  required: ['summary', 'findings', 'sources', 'caveats', 'actionable_guidance']
}

// Phase 1: Plan search queries
phase('Plan')
log('Planning search queries for Claude vs OpenAI prompt caching research...')

const plan = await agent(
  `You are a research planner. Generate a comprehensive set of web search queries to research this topic:

  "Compare prompt caching strategies of Claude (Anthropic) versus OpenAI for reducing LLM API cost and latency in 2025-2026."

  We need to cover:
  1. Claude prompt caching: cache_control parameter, cache breakpoints, TTL, pricing (write vs read multipliers)
  2. OpenAI prompt caching: how it works, automatic vs manual, TTL, pricing
  3. Prefix stability requirements for both
  4. Actionable guidance for coding agents to maximize cache hits
  5. Recent updates in 2025-2026

  Generate 8-10 specific search queries that will find official documentation, blog posts, and credible analysis.
  Return JSON with queries array and rationale.`,
  { phase: 'Plan', schema: SEARCH_SCHEMA }
)

log(`Planned ${plan.queries.length} search queries: ${plan.queries.slice(0, 3).join(', ')}...`)

// Phase 2: Fan-out searches
phase('Search')
log('Running parallel web searches...')

const searchResults = await parallel(plan.queries.map(query => () =>
  agent(
    `Search the web for: "${query}"

    Find the most relevant and credible results about Claude/OpenAI prompt caching.
    Prefer official documentation (docs.anthropic.com, platform.openai.com), official blogs, and well-known AI engineering blogs.
    Return up to 3 most relevant results with URL, title, snippet, and why it's relevant.`,
    { label: `search:${query.slice(0, 40)}`, phase: 'Search', schema: SEARCH_RESULTS_SCHEMA }
  )
))

const allSearchResults = searchResults.filter(Boolean).flatMap(r => r.results)
const uniqueUrls = [...new Set(allSearchResults.map(r => r.url))]
log(`Found ${allSearchResults.length} results across ${uniqueUrls.length} unique URLs`)

// Deduplicate and prioritize URLs
const prioritizedUrls = allSearchResults
  .reduce((acc, r) => {
    if (!acc.find(x => x.url === r.url)) acc.push(r)
    return acc
  }, [])
  .sort((a, b) => {
    const priority = (url) => {
      if (url.includes('docs.anthropic.com')) return 0
      if (url.includes('platform.openai.com')) return 0
      if (url.includes('anthropic.com')) return 1
      if (url.includes('openai.com')) return 1
      return 2
    }
    return priority(a.url) - priority(b.url)
  })
  .slice(0, 15)

log(`Fetching top ${prioritizedUrls.length} prioritized sources...`)

// Phase 3: Fetch and extract content
phase('Fetch')
const fetchedSources = await pipeline(
  prioritizedUrls,
  source => agent(
    `Fetch and extract key information from this URL about prompt caching:
    URL: ${source.url}
    Title: ${source.title}

    Extract:
    - Key facts about prompt caching (TTL, pricing, breakpoints, cache_control syntax)
    - Relevant direct quotes
    - Cache-specific details (TTL values, pricing multipliers, minimum token thresholds)

    If you cannot fetch the page, use the snippet: "${source.snippet}" and note it was not directly fetched.
    Return structured data.`,
    { label: `fetch:${source.title.slice(0, 40)}`, phase: 'Fetch', schema: FETCH_SCHEMA }
  )
)

const validSources = fetchedSources.filter(Boolean)
log(`Successfully extracted data from ${validSources.length} sources`)

// Phase 4: Verify key claims
phase('Verify')
const KEY_CLAIMS = [
  'Claude prompt caching requires minimum 1024 tokens for Claude-3 models and 2048 for Claude-3.5/3.7',
  'Claude cache TTL is 5 minutes by default (ephemeral), with an option for 1-hour TTL',
  'Claude cache write costs 25% more than base input token price; cache read costs 90% less than base',
  'OpenAI prompt caching is automatic (no explicit cache_control needed) with 50% discount on cache hits',
  'OpenAI cache TTL is typically 5-10 minutes and longer during off-peak hours',
  'For coding agents, system prompt + tools/tool definitions should be placed at the start for maximum cache hits'
]

const verifications = await parallel(KEY_CLAIMS.map(claim => () =>
  agent(
    `Verify this claim about LLM prompt caching using the following source data:

    CLAIM: "${claim}"

    SOURCE DATA:
    ${JSON.stringify(validSources.map(s => ({ url: s.url, facts: s.key_facts, quotes: s.relevant_quotes })).slice(0, 8), null, 2)}

    Check if the claim is confirmed, refuted, or uncertain based on the sources.
    Cite specific sources that support or contradict the claim.`,
    { label: `verify:${claim.slice(0, 50)}`, phase: 'Verify', schema: VERIFY_SCHEMA }
  )
))

const verifiedClaims = verifications.filter(Boolean)
log(`Verified ${verifiedClaims.length} claims: ${verifiedClaims.filter(v => v.verdict === 'confirmed').length} confirmed, ${verifiedClaims.filter(v => v.verdict === 'refuted').length} refuted, ${verifiedClaims.filter(v => v.verdict === 'uncertain').length} uncertain`)

// Phase 5: Synthesize final report
phase('Synthesize')
log('Synthesizing final research report...')

const report = await agent(
  `You are a technical research synthesizer. Create a comprehensive, cited research report on:

  "Claude vs OpenAI Prompt Caching Strategies 2025-2026: Cost & Latency Optimization"

  Use these verified findings and sources:

  VERIFIED CLAIMS:
  ${JSON.stringify(verifiedClaims, null, 2)}

  SOURCE DETAILS:
  ${JSON.stringify(validSources.slice(0, 10).map(s => ({
    url: s.url,
    title: s.title,
    key_facts: s.key_facts,
    cache_details: s.cache_details
  })), null, 2)}

  SEARCH RESULTS (additional context):
  ${JSON.stringify(allSearchResults.slice(0, 20).map(r => ({ url: r.url, title: r.title, snippet: r.snippet })), null, 2)}

  Structure the report with these sections as findings:
  1. How Cache Breakpoints / cache_control work (Claude vs OpenAI)
  2. Cache TTL and lifetime
  3. Cache write vs read pricing multipliers
  4. Prompt-prefix stability requirements
  5. Actionable guidance for coding agents to maximize cache hits
  6. Key differences and tradeoffs between Claude and OpenAI approaches

  For actionable_guidance, provide 5-8 concrete, specific steps a coding agent should take.
  For caveats, note any uncertainty, gaps, or things that may have changed.
  Cite real URLs in sources array.

  Return a complete JSON report.`,
  { phase: 'Synthesize', schema: SYNTHESIS_SCHEMA }
)

log('Research complete!')

return {
  ...report,
  metadata: {
    queries_run: plan.queries.length,
    sources_searched: allSearchResults.length,
    sources_fetched: validSources.length,
    claims_verified: verifiedClaims.length
  }
}
